noncompliant:
int values[5] = {1, 2, 3, 4, 5};
int first = *values;      // Noncompliant: implicit access to first element
printf("%d", *values);    // Noncompliant: dereferencing array name

struct Point {
  int x, y;
};
struct Point points[3];
int x = points->x;        // Noncompliant: using arrow operator on array

compliant:
int values[5] = {1, 2, 3, 4, 5};
int first = values[0];    // Compliant: explicit subscript access
printf("%d", values[0]); // Compliant: using subscript operator

struct Point {
  int x, y;
};
struct Point points[3];
int x = points[0].x;      // Compliant: explicit access to first element
